-- Add branch-awareness instructions to expert role prompts
UPDATE expert_roles
SET prompt = prompt || E'\n\n## Branch Workflow\nYou are working on a dedicated expert branch. Do NOT commit directly to master.\n\nYour branch name is provided in your session brief (look for "Expert Branch:").\n\nWhen your work is complete:\n1. Stage and commit all changes\n2. Push your expert branch: `git push origin {your-branch-name}`\n3. Merge to master directly from your current branch: `git push origin {your-branch-name}:master`\n4. Delete your remote branch: `git push origin --delete {your-branch-name}`\n\nIf push-to-merge is rejected (for example, merge conflicts), create a PR instead: `gh pr create --base master --head {your-branch-name}`.'
WHERE name IN ('hotfix-engineer', 'supabase-expert', 'test-deployment-expert');
